-- Data-only migration: session 2026-05-13 cleanup and content fill.
-- Idempotent: UPDATEs are no-ops if already applied; INSERTs guarded by WHERE NOT EXISTS.
-- Does NOT modify User, Order, Attempt, Session, AdminLog tables.
-- Prisma wraps each migration in its own transaction, so no BEGIN/COMMIT below.

-- Ensure pgcrypto is available for gen_random_uuid() used by question INSERTs.
CREATE EXTENSION IF NOT EXISTS pgcrypto;


-- 1) Soft-delete legacy parent exams (no -P suffix; superseded by P-variants).
UPDATE "Exam" SET "deletedAt" = NOW(), "published" = false
  WHERE code = ANY(ARRAY['AIF-C01', 'CLF-C02', 'DEA-C01', 'DVA-C02', 'DOP-C02', 'AI-102-P']) AND "deletedAt" IS NULL;

-- 2) Unpublish standalone exams (no bundle membership; unbuyable under bundle-only-pricing).
UPDATE "Exam" SET "published" = false
  WHERE code = ANY(ARRAY['AIP-C01', 'ANS-C01', 'SAP-C02', 'SCS-C03', 'SOA-C03', 'AZ-900', 'CCA-F', 'ITIL4-F-P7', 'CLSSGB-P1', 'AZ-500-P1', 'TDS-P5']) AND "published" = true;

-- 3) Rename non-standard codes to canonical short codes.
-- AI-102-OFFICIAL -> AI-102-P5 (with slug/title/label updates)
UPDATE "Exam" SET code='AI-102-P5', slug='microsoft-ai-102-p5',
  title='Microsoft Azure AI Engineer Associate (AI-102) (Practice Exam 5)',
  label='Practice Exam 5'
  WHERE code = 'AI-102-OFFICIAL';

UPDATE "Exam" SET code='PMLE-P1' WHERE code = 'PRO-ML-P1';
UPDATE "Exam" SET code='PMLE-P2' WHERE code = 'PRO-ML-P2';
UPDATE "Exam" SET code='PMLE-P3' WHERE code = 'PRO-ML-P3';
UPDATE "Exam" SET code='PMLE-P4' WHERE code = 'PRO-ML-P4';
UPDATE "Exam" SET code='PMLE-P5' WHERE code = 'PRO-ML-P5';
UPDATE "Exam" SET code='PMLE-P6' WHERE code = 'PRO-ML-P6';

UPDATE "Exam" SET code='GHF-P1' WHERE code = 'GH-FOUND-P1';
UPDATE "Exam" SET code='GHF-P2' WHERE code = 'GH-FOUND-P2';
UPDATE "Exam" SET code='GHF-P3' WHERE code = 'GH-FOUND-P3';
UPDATE "Exam" SET code='GHF-P4' WHERE code = 'GH-FOUND-P4';

-- 4) Standardize questionCount to match official vendor specs.
UPDATE "Exam" SET "questionCount" = 65
  WHERE code LIKE 'AIF-C01-P%' AND "questionCount" <> 65;
UPDATE "Exam" SET "questionCount" = 65
  WHERE code LIKE 'DEA-C01-P%' AND "questionCount" <> 65;
UPDATE "Exam" SET "questionCount" = 75
  WHERE code LIKE 'DOP-C02-P%' AND "questionCount" <> 75;

-- 5) Insert AI-generated DRAFT questions. Re-run-safe via WHERE NOT EXISTS.
-- gen_random_uuid() is used for question IDs (cuid is fine; we use UUID strings here).

-- AIF-C01-P1: 35 new questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data scientist wants to build, train, and deploy a custom machine learning model using fully managed infrastructure without setting up servers. Which AWS service is specifically designed to meet this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Amazon Rekognition"},{"id":"b","text":"Amazon SageMaker AI"},{"id":"c","text":"Amazon Lex"},{"id":"d","text":"Amazon Textract"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$According to the source material, 'Amazon SageMaker AI is a fully managed machine learning (ML) service. With SageMaker AI, data scientists and developers can quickly build, train, and deploy ML models into a production-ready hosted environment.' The other options are pre-built AI services for specific tasks: Rekognition handles computer vision, Lex builds conversational chatbots, and Textract extracts text from documents — none of them provide a general-purpose environment for custom model development.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/sagemaker/latest/dg/whatis.html","label":"What is Amazon SageMaker AI?"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data scientist wants to build, train, and deploy a custom machine learning model using fully managed infrastructure without setting up servers. Which AWS service is specifically designed to meet this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning team is working with a large dataset of customer records that contains NO labels. They want to discover natural groupings within the data. Which type of machine learning approach should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Supervised learning — regression"},{"id":"b","text":"Reinforcement learning"},{"id":"c","text":"Supervised learning — classification"},{"id":"d","text":"Unsupervised learning — clustering"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The source material states: 'Unsupervised learning: model finds patterns in unlabeled data (clustering, anomaly detection).' Because the dataset has no labels, supervised approaches (regression and classification) cannot be used, as they require labeled data. Reinforcement learning involves an agent interacting with an environment for rewards, which does not apply here. Unsupervised clustering is the correct approach for discovering natural groupings in unlabeled data.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS Machine Learning Concepts Overview"},{"url":"https://explore.skillbuilder.aws/learn/course/internal/view/elearning/134/aws-cloud-practitioner-essentials","label":"Types of Machine Learning — AWS Training"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning team is working with a large dataset of customer records that contains NO labels. They want to discover natural groupings within the data. Which type of machine learning approach should they use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An autonomous robotics company is training a control system that learns to navigate a warehouse floor by receiving positive feedback when it avoids obstacles and reaches its destination. Which ML paradigm best describes this training approach?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Supervised learning"},{"id":"b","text":"Semi-supervised learning"},{"id":"c","text":"Reinforcement learning"},{"id":"d","text":"Unsupervised learning"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material defines reinforcement learning as: 'agent learns by interacting with an environment and receiving rewards.' The robot (agent) interacts with the warehouse environment and receives positive feedback (rewards) when it succeeds. This is the textbook definition of reinforcement learning. Supervised learning requires labeled data pairs, unsupervised learning finds patterns in unlabeled data, and semi-supervised learning is not mentioned in the source material.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS Machine Learning AI Services"},{"url":"https://aws.amazon.com/blogs/machine-learning/category/artificial-intelligence/reinforcement-learning/","label":"Reinforcement Learning with AWS"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An autonomous robotics company is training a control system that learns to navigate a warehouse floor by receiving positive feedback when it avoids obstacles and reaches its destination. Which ML paradigm best describes this training approach?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer needs to automatically convert audio recordings from customer support calls into searchable text transcripts. Which AWS AI service is the MOST appropriate choice?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Amazon Polly"},{"id":"b","text":"Amazon Transcribe"},{"id":"c","text":"Amazon Translate"},{"id":"d","text":"Amazon Textract"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material describes Amazon Transcribe as: 'Automatically convert speech to text with a feature-rich API for real-time and recorded audio/video content.' This directly matches the use case of converting audio call recordings to text. Amazon Polly does the reverse — it converts text to speech. Amazon Translate handles language translation. Amazon Textract extracts text from scanned documents, not audio.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/transcribe/","label":"Amazon Transcribe – Speech to Text"},{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS AI Services Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer needs to automatically convert audio recordings from customer support calls into searchable text transcripts. Which AWS AI service is the MOST appropriate choice?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company wants to add a voice assistant feature to their mobile app so that the app can read out order confirmations to customers in a natural-sounding voice. Which AWS managed AI service should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Amazon Lex"},{"id":"b","text":"Amazon Transcribe"},{"id":"c","text":"Amazon Rekognition"},{"id":"d","text":"Amazon Polly"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The source material states: 'Amazon Polly: Turn text into lifelike speech to build speech-enabled products.' Converting written order confirmation text into a natural-sounding voice output is precisely the text-to-speech use case Polly is built for. Amazon Lex is for building conversational chatbots, Amazon Transcribe converts speech to text (the reverse direction), and Amazon Rekognition is a computer vision service for images and videos.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/polly/","label":"Amazon Polly – Text to Speech"},{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS AI Services Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company wants to add a voice assistant feature to their mobile app so that the app can read out order confirmations to customers in a natural-sounding voice. Which AWS managed AI service should they use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A financial institution wants to scan thousands of paper-based forms and automatically extract the printed and handwritten fields — such as account numbers and signatures — into a structured digital format. Which AWS service is MOST suitable?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Amazon Translate"},{"id":"b","text":"Amazon Rekognition"},{"id":"c","text":"Amazon Textract"},{"id":"d","text":"Amazon Comprehend"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material describes Amazon Textract as a service that 'Automatically extracts text, handwriting, and data from scanned documents.' This precisely matches the requirement to digitize paper forms containing printed text and handwriting. Amazon Rekognition performs general computer vision tasks (object detection, facial recognition) but is not specialized for document extraction. Amazon Translate handles language translation. Amazon Comprehend (not in the source material) performs NLP but does not extract data from scanned images.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/textract/","label":"Amazon Textract – Document Text Extraction"},{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS AI Services Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A financial institution wants to scan thousands of paper-based forms and automatically extract the printed and handwritten fields — such as account numbers and signatures — into a structured digital format. Which AWS service is MOST suitable?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning engineer has finished training a model and now needs to assess how well the model performs before releasing it. According to the standard ML lifecycle, which step immediately follows model training?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Data collection"},{"id":"b","text":"Model deployment"},{"id":"c","text":"Model evaluation"},{"id":"d","text":"Feature engineering"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material explicitly lists the ML lifecycle as: 'data collection → data preparation/feature engineering → model training → model evaluation → model deployment → monitoring → retraining.' Model evaluation directly follows model training. Skipping evaluation and going straight to deployment risks releasing an underperforming model. Data collection and feature engineering are earlier stages, while deployment comes after evaluation.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS Machine Learning AI Services"},{"url":"https://docs.aws.amazon.com/sagemaker/latest/dg/how-it-works-mlconcepts.html","label":"ML Lifecycle with Amazon SageMaker"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning engineer has finished training a model and now needs to assess how well the model performs before releasing it. According to the standard ML lifecycle, which step immediately follows model training?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An e-commerce platform needs to detect fraudulent transactions in near-real time by finding unusual patterns that deviate from normal purchasing behavior, without having any pre-labeled fraud examples. Which ML approach is BEST suited for this use case?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Supervised learning — binary classification"},{"id":"b","text":"Unsupervised learning — anomaly detection"},{"id":"c","text":"Reinforcement learning"},{"id":"d","text":"Supervised learning — regression"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Unsupervised learning: model finds patterns in unlabeled data (clustering, anomaly detection).' Because there are no pre-labeled fraud examples, supervised learning cannot be applied. Anomaly detection — an unsupervised technique — identifies data points that deviate significantly from established patterns, making it the right fit for catching unusual transactions without labeled data. Reinforcement learning is designed for sequential decision-making with reward signals, not batch pattern detection.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS Machine Learning AI Services"},{"url":"https://docs.aws.amazon.com/sagemaker/latest/dg/randomcutforest.html","label":"Anomaly Detection with Amazon SageMaker"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An e-commerce platform needs to detect fraudulent transactions in near-real time by finding unusual patterns that deviate from normal purchasing behavior, without having any pre-labeled fraud examples. Which ML approach is BEST suited for this use case?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company wants to build a customer service chatbot that can understand natural language questions about order status and respond conversationally. Which AWS managed AI service is purpose-built for this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Amazon Rekognition"},{"id":"b","text":"Amazon Polly"},{"id":"c","text":"Amazon Lex"},{"id":"d","text":"Amazon Textract"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material defines Amazon Lex as a service to 'Design, build, test, and deploy conversational interfaces (chatbots) with advanced natural language models.' A customer service chatbot that interprets and responds to natural language queries is exactly the conversational interface use case Lex is built for. Amazon Rekognition handles image and video analysis, Amazon Polly converts text to speech, and Amazon Textract extracts data from scanned documents — none of these are designed for conversational chatbot development.$patch$, $patch$Fundamentals of AI and ML$patch$,
         3, $json$[{"url":"https://aws.amazon.com/lex/","label":"Amazon Lex – Conversational AI"},{"url":"https://aws.amazon.com/machine-learning/ai-services/","label":"AWS AI Services Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company wants to build a customer service chatbot that can understand natural language questions about order status and respond conversationally. Which AWS managed AI service is purpose-built for this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer wants to invoke an Amazon Bedrock foundation model using a single API that works consistently across models from different providers without changing the request structure. Which Bedrock API best satisfies this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"InvokeModel API"},{"id":"b","text":"Converse API"},{"id":"c","text":"Messages API"},{"id":"d","text":"Chat Completions API"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The Bedrock documentation describes the Converse API (boto3 bedrock-runtime client) as a 'unified, model-agnostic chat interface,' meaning it accepts the same request shape regardless of the underlying provider. The InvokeModel API requires a provider-specific request body, making it unsuitable for a provider-agnostic solution. The Messages API is specific to Anthropic/Claude models, and the Chat Completions API is an OpenAI-compatible interface for OpenAI models on Bedrock — neither is universal across all providers.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/conversation-inference.html","label":"Amazon Bedrock API Overview – Converse API"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer wants to invoke an Amazon Bedrock foundation model using a single API that works consistently across models from different providers without changing the request structure. Which Bedrock API best satisfies this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An AI engineer needs to reduce the determinism of a foundation model's responses in Amazon Bedrock so that the model produces more varied creative outputs. Which inference parameter should the engineer increase?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"max_tokens"},{"id":"b","text":"stop_sequences"},{"id":"c","text":"temperature"},{"id":"d","text":"top_k"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$According to the source material, 'temperature controls randomness; lower = more deterministic.' Therefore, increasing temperature increases randomness and produces more varied outputs. max_tokens caps the output length and does not affect creativity. stop_sequences define where the model stops generating, which is unrelated to variability. top_k limits the candidate token pool but is less directly associated with the determinism-to-creativity axis than temperature.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/inference-parameters.html","label":"Amazon Bedrock Inference Parameters"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An AI engineer needs to reduce the determinism of a foundation model's responses in Amazon Bedrock so that the model produces more varied creative outputs. Which inference parameter should the engineer increase?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company wants to ground an Amazon Bedrock generative AI application in its proprietary internal documents stored in Amazon S3 so that the model answers questions using up-to-date company data rather than only its pre-training knowledge. Which Bedrock feature is designed for this purpose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Bedrock Guardrails"},{"id":"b","text":"Provisioned Throughput"},{"id":"c","text":"Knowledge Bases for Amazon Bedrock"},{"id":"d","text":"Model Evaluation"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states that 'Knowledge Bases for Amazon Bedrock' is a managed RAG service that lets you 'ingest documents from S3, chunk, embed, and retrieve into a vector store,' which is exactly the mechanism for grounding a model in private or up-to-date data. Bedrock Guardrails provide safety filters. Provisioned Throughput reserves capacity for predictable latency. Model Evaluation compares model performance against custom metrics — none of these address document grounding.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/knowledge-base.html","label":"Knowledge Bases for Amazon Bedrock"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company wants to ground an Amazon Bedrock generative AI application in its proprietary internal documents stored in Amazon S3 so that the model answers questions using up-to-date company data rather than only its pre-training knowledge. Which Bedrock feature is designed for this purpose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which generative AI prompting technique involves providing the model with several labeled input-output examples inside the prompt before asking it to process a new input?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Zero-shot prompting"},{"id":"b","text":"Chain-of-thought prompting"},{"id":"c","text":"Few-shot prompting"},{"id":"d","text":"Retrieval-augmented generation"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material defines few-shot prompting as 'provide examples in prompt,' which matches the technique of supplying labeled input-output pairs to guide the model. Zero-shot prompting provides no examples. Chain-of-thought prompting asks the model to reason step by step and does not necessarily include labeled examples. Retrieval-augmented generation retrieves external documents rather than embedding examples directly in the prompt.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://aws.amazon.com/blogs/machine-learning/prompt-engineering-techniques/","label":"Prompt Engineering Concepts – AWS Machine Learning Blog"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which generative AI prompting technique involves providing the model with several labeled input-output examples inside the prompt before asking it to process a new input?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning team is building a semantic search feature that must find documents conceptually similar to a user's query even when exact keywords do not match. Which representation of text makes this possible in a vector store?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tokenized keyword lists"},{"id":"b","text":"Embeddings"},{"id":"c","text":"Stop sequences"},{"id":"d","text":"Fine-tuned model weights"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states that 'Embeddings: numeric vector representations of text/images used for semantic search and RAG.' Embeddings capture semantic meaning so that conceptually similar content has similar vectors, enabling similarity search beyond keyword matching. Tokenized keyword lists do not capture semantic meaning. Stop sequences are inference parameters that halt generation. Fine-tuned model weights adapt a model but are not a representation stored in a vector store for retrieval.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/embeddings.html","label":"Amazon Bedrock Embeddings"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning team is building a semantic search feature that must find documents conceptually similar to a user's query even when exact keywords do not match. Which representation of text makes this possible in a vector store?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization needs to adapt an Amazon Bedrock foundation model to a highly specialized medical terminology domain. The team has a large corpus of unlabeled medical text and wants the model to learn domain-specific language patterns before any task-specific fine-tuning. Which Bedrock Custom Models capability should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Fine-tuning with labeled question-answer pairs"},{"id":"b","text":"Continued pre-training on unlabeled domain text"},{"id":"c","text":"Provisioned Throughput reservation"},{"id":"d","text":"Bedrock Guardrails configuration"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material lists 'Custom Models — fine-tuning and continued pre-training for domain adaptation.' Continued pre-training is the process of further training a model on unlabeled domain-specific data to internalize new vocabulary and patterns, which is ideal for specialized corpora like medical text. Fine-tuning with labeled pairs is used for task-specific adaptation after domain language is learned. Provisioned Throughput addresses capacity, not model adaptation. Guardrails address safety filters, not domain knowledge.$patch$, $patch$Fundamentals of Generative AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/custom-models.html","label":"Custom Models – Amazon Bedrock"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'AIF-C01-P1'
