INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A financial services company using Amazon Bedrock needs to encrypt model artifacts, training data, and knowledge bases with keys that they fully control and can rotate on a custom schedule. Which AWS service and key type should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"AWS Certificate Manager (ACM) with private CA certificates"},{"id":"b","text":"AWS KMS with AWS-managed keys (aws/bedrock)"},{"id":"c","text":"AWS KMS with customer-managed keys (CMKs)"},{"id":"d","text":"AWS Secrets Manager with automatic secret rotation"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'KMS (Key Management Service): customer-managed keys (CMKs) for encryption at rest of model artifacts, training data, knowledge bases, and conversation logs.' CMKs give customers full control over key policies, rotation schedules, and auditing via CloudTrail. AWS-managed keys (option B) are controlled by AWS and cannot be customized with customer-defined rotation schedules or fine-grained policies. ACM manages SSL/TLS certificates for encryption in transit, not data at rest. Secrets Manager stores application secrets and credentials, not encryption keys for Bedrock data assets.$patch$, $patch$Security, Compliance, and Governance for AI$patch$,
         3, $json$[{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/encryption-at-rest.html","label":"Amazon Bedrock – Encryption at Rest"},{"url":"https://docs.aws.amazon.com/bedrock/latest/userguide/security.html","label":"Amazon Bedrock Security"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
